@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="_container">
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int TimeoutSeconds { get; set; } = 300;
    [Parameter] public EventCallback OnIdle { get; set; }
    [Parameter] public EventCallback OnActive { get; set; }

    private ElementReference _container;
    private IJSObjectReference? _module;
    private DotNetObjectReference<UserActivityTracker>? _dotNetRef;

    private bool _isIdle;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/UserActivityTracker.razor.js");
            await _module.InvokeVoidAsync("initialize", _container, _dotNetRef, TimeoutSeconds * 1000);
        }
    }

    [JSInvokable]
    public async Task OnUserIdle()
    {
        if (!_isIdle)
        {
            _isIdle = true;
            await OnIdle.InvokeAsync();
        }
    }

    [JSInvokable]
    public async Task OnUserActive()
    {
        if (_isIdle)
        {
            _isIdle = false;
            await OnActive.InvokeAsync();
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            try
            {
                await _module.InvokeVoidAsync("dispose");
                await _module.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
        _dotNetRef?.Dispose();
    }
}

let timer = null;
let dotNetHelper = null;
let container = null;
let timeoutMs = 300000;
let isIdle = false;

const events = ["mousemove", "keydown", "click", "scroll"];

function handleActivity() {
    if (timer) clearTimeout(timer);

    if (isIdle) {
        isIdle = false;
        dotNetHelper.invokeMethodAsync("OnUserActive");
    }

    timer = setTimeout(() => {
        isIdle = true;
        dotNetHelper.invokeMethodAsync("OnUserIdle");
    }, timeoutMs);
}

function onEvent(e) {
    handleActivity();
}

export function initialize(element, helper, timeout) {
    container = element;
    dotNetHelper = helper;
    timeoutMs = timeout;
    isIdle = false;

    events.forEach(evt => container.addEventListener(evt, onEvent, { passive: true }));

    // Start the initial idle timer
    timer = setTimeout(() => {
        isIdle = true;
        dotNetHelper.invokeMethodAsync("OnUserIdle");
    }, timeoutMs);
}

export function dispose() {
    if (timer) {
        clearTimeout(timer);
        timer = null;
    }
    if (container) {
        events.forEach(evt => container.removeEventListener(evt, onEvent));
        container = null;
    }
    dotNetHelper = null;
}

